# Test function

@pytest.mark.parametrize("m1, m2, chi1x, chi1y, chi1z, chi2x, chi2y, chi2z, e0, f0, f1, enhancementFunc, Omega_final, et_final, l_final, lamb_final, S1x_final, S1y_final, S1z_final, \
                          S2x_final, S2y_final, S2z_final, LNhatx_final, LNhaty_final, LNhatz_final, Phatx_final, Phaty_final, Phatz_final, k_final, Omega_norm, et_norm, l_norm, lamb_norm, \
                          S1x_norm, S1y_norm, S1z_norm, S2x_norm, S2y_norm, S2z_norm, LNhatx_norm, LNhaty_norm, LNhatz_norm, Phatx_norm, Phaty_norm, Phatz_norm, k_norm", test_data)
def test_ecc_spin_evol(m1, m2, chi1x, chi1y, chi1z, chi2x, chi2y, chi2z, e0, f0, f1, enhancementFunc, Omega_final, et_final, l_final, lamb_final, S1x_final, S1y_final, S1z_final,
                       S2x_final, S2y_final, S2z_final, LNhatx_final, LNhaty_final, LNhatz_final, Phatx_final, Phaty_final, Phatz_final, k_final, Omega_norm, et_norm, l_norm, lamb_norm,
                       S1x_norm, S1y_norm, S1z_norm, S2x_norm, S2y_norm, S2z_norm, LNhatx_norm, LNhaty_norm, LNhatz_norm, Phatx_norm, Phaty_norm, Phatz_norm, k_norm):
    """
    Regression test for SimInspiralSpinTaylorPNEccentricEvolveOrbit()

    m1, m2: Detector frame masses of the binary, in kg
    chi1x, chi1y, chi1z, chi2x, chi2y, chi2z: Cartesian components of the binary's dimensionless spins
    e0: Initial eccentricity
    f0, f1: Initial and final frequencies, in Hz

    enhancementFunc: Enhancement function setting

    Omega_final, ..., k_final: Final values from evolution
    Omega_norm, ..., k_norm: L^2 norms of time series from evolution
    """

    rtol = 1.e-4

    dictparams = {'deltaT': 1./1024, 'm1_SI': m1, 'm2_SI': m2, 'fStart': f0, 'fEnd': f1, 's1x': chi1x, 's1y': chi1y, 's1z': chi1z,'s2x': chi2x, 's2y': chi2y, 's2z': chi2z, 'lnhatx': 0.,
                  'lnhaty': 0., 'lnhatz': 1., 'eccentricity': e0, 'l0': 0, 'lamb0': 0, 'phatx': 1, 'phaty': 0, 'phatz': 0, 'spinO': 4, 'EccOrder': -1, 'phaseO': 6, 'enhancementFunc': enhancementFunc, 'type': 0, 'LALparams': None}

    # Check FullSeries evolution
    Omega, et, l, lamb, S1x, S1y, S1z, S2x, S2y, S2z, LNhatx, LNhaty, LNhatz, Phatx, Phaty, Phatz, k = SimInspiralSpinTaylorPNEccentricEvolveOrbit(**dictparams)

    data = np.array([Omega.data.data, et.data.data, l.data.data, lamb.data.data, S1x.data.data, S1y.data.data, S1z.data.data, S2x.data.data, S2y.data.data, S2z.data.data,
                     LNhatx.data.data, LNhaty.data.data, LNhatz.data.data, Phatx.data.data, Phaty.data.data, Phatz.data.data, k.data.data])

    norms = np.linalg.norm(data, axis=-1)

    np.testing.assert_allclose([norms[0], norms[1], norms[2], norms[3], norms[4], norms[5], norms[6], norms[7], norms[8], norms[9], norms[10], norms[11], norms[12], norms[13], norms[14], norms[15],
                                norms[16]],
                               [Omega_norm, et_norm, l_norm, lamb_norm, S1x_norm, S1y_norm, S1z_norm, S2x_norm, S2y_norm, S2z_norm, LNhatx_norm, LNhaty_norm, LNhatz_norm, Phatx_norm,
                                Phaty_norm, Phatz_norm, k_norm],
                               err_msg="Check of norms of FullSeries evolution failed.", rtol=rtol)

    # Check FullSeries evolution when computing the initial value of k using SimInspiralSpinTaylorEccentricComputePeriastronPrecession()
    k_init = SimInspiralSpinTaylorEccentricComputePeriastronPrecession(f0, m1, m2, chi1x, chi1y, chi1z, chi2x, chi2y, chi2z, 0., 0., 1., e0, 4, 6)

    LALpars = lal.CreateDict()
    SimInspiralWaveformParamsInsertInitialPeriastronPrecession(LALpars, k_init)
    dictparams['LALparams'] = LALpars

    Omega, et, l, lamb, S1x, S1y, S1z, S2x, S2y, S2z, LNhatx, LNhaty, LNhatz, Phatx, Phaty, Phatz, k = SimInspiralSpinTaylorPNEccentricEvolveOrbit(**dictparams)

    data = np.array([Omega.data.data, et.data.data, l.data.data, lamb.data.data, S1x.data.data, S1y.data.data, S1z.data.data, S2x.data.data, S2y.data.data, S2z.data.data,
                     LNhatx.data.data, LNhaty.data.data, LNhatz.data.data, Phatx.data.data, Phaty.data.data, Phatz.data.data, k.data.data])

    norms = np.linalg.norm(data, axis=-1)

    np.testing.assert_allclose([norms[0], norms[1], norms[2], norms[3], norms[4], norms[5], norms[6], norms[7], norms[8], norms[9], norms[10], norms[11], norms[12], norms[13], norms[14], norms[15],
                                norms[16]],
                               [Omega_norm, et_norm, l_norm, lamb_norm, S1x_norm, S1y_norm, S1z_norm, S2x_norm, S2y_norm, S2z_norm, LNhatx_norm, LNhaty_norm, LNhatz_norm, Phatx_norm,
                                Phaty_norm, Phatz_norm, k_norm],
                               err_msg="Check of norms of FullSeries evolution and computing the initial value of k using SimInspiralSpinTaylorEccentricComputePeriastronPrecession() failed.", rtol=rtol)

    # Check FinalValue evolution

    dictparams['type'] = 1

    dictparams['LALparams'] = None

    Omega, et, l, lamb, S1x, S1y, S1z, S2x, S2y, S2z, LNhatx, LNhaty, LNhatz, Phatx, Phaty, Phatz, k = SimInspiralSpinTaylorPNEccentricEvolveOrbit(**dictparams)

    np.testing.assert_allclose([Omega.data.data[0], et.data.data[0], l.data.data[0], lamb.data.data[0], S1x.data.data[0], S1y.data.data[0], S1z.data.data[0],
                                S2x.data.data[0], S2y.data.data[0], S2z.data.data[0], LNhatx.data.data[0], LNhaty.data.data[0], LNhatz.data.data[0], Phatx.data.data[0], Phaty.data.data[0],
                                Phatz.data.data[0], k.data.data[0]],
                               [Omega_final, et_final, l_final, lamb_final, S1x_final, S1y_final, S1z_final, S2x_final, S2y_final, S2z_final, LNhatx_final, LNhaty_final,
                                LNhatz_final, Phatx_final, Phaty_final, Phatz_final, k_final], err_msg="Check of final values from FinalValue evolution failed.", rtol=rtol)

# Run tests

if __name__ == '__main__':
    args = sys.argv[1:] or ["-v", "-rs", "--junit-xml=junit-ecc_spin_evol.xml"]
    sys.exit(pytest.main(args=[__file__] + args))
